module RefModule(  
    input clk,  
    input reset,  
    input branch_outcome,  
    output reg prediction  
);  
    reg [1:0] unused_counter;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            unused_counter <= 2'b00; // Start at Strongly Not Taken  
            prediction <= 1'b0;  
        end else begin  
            prediction <= unused_counter[1]; // Output prediction based on MSB of unused_counter  
            case (unused_counter)  
                2'b00: if (branch_outcome) unused_counter <= 2'b01; else unused_counter <= 2'b00;  
                2'b01: if (branch_outcome) unused_counter <= 2'b10; else unused_counter <= 2'b00;  
                2'b10: if (branch_outcome) unused_counter <= 2'b11; else unused_counter <= 2'b01;  
                2'b11: if (branch_outcome) unused_counter <= 2'b11; else unused_counter <= 2'b10;  
                default: unused_counter <= 2'b00;  
            endcase  
        end  
    end  
endmodule
